@layer mergora.components {
  .mrg-citation {
    display: inline-flex;
    flex-wrap: wrap;
    align-items: baseline;
    gap: var(--mrg-semantic-space-inline-xs);
    color: var(--mrg-semantic-color-foreground-primary);
    font-family: var(--mrg-semantic-font-family-prose);
  }

  .mrg-citation > a,
  .mrg-citation > span:first-child {
    padding-inline: var(--mrg-semantic-space-inset-xs);
    border: var(--mrg-semantic-border-width-default) solid var(--mrg-semantic-color-accent-border);
    border-radius: var(--mrg-semantic-radius-compact);
    color: var(--mrg-semantic-color-accent-foreground-on-subtle);
    background: var(--mrg-semantic-color-accent-background-subtle);
    font-size: var(--mrg-semantic-font-size-label);
    font-weight: var(--mrg-semantic-font-weight-label);
    text-decoration-thickness: var(--mrg-semantic-border-width-default);
    text-underline-offset: 0.15em;
  }

  .mrg-citation[data-safe-url="false"] > span:first-child {
    border-color: var(--mrg-semantic-color-status-warning-border);
    color: var(--mrg-semantic-color-status-warning-foreground);
    background: var(--mrg-semantic-color-status-warning-background);
  }

  .mrg-citation [data-slot="citation-source-detail"] {
    display: inline-flex;
    flex-wrap: wrap;
    gap: var(--mrg-semantic-space-inline-xs);
    max-inline-size: var(--mrg-semantic-size-content-prose);
    padding-block: var(--mrg-semantic-space-inset-xs);
    border-block-end: var(--mrg-semantic-border-width-default) solid
      var(--mrg-semantic-color-border-default);
    color: var(--mrg-semantic-color-foreground-muted);
    font-size: var(--mrg-semantic-font-size-label);
    overflow-wrap: anywhere;
  }

  .mrg-citation a:focus-visible {
    box-shadow: 0 0 0 var(--mrg-semantic-focus-width)
      var(--mrg-semantic-color-focus-contrast-background);
    outline: var(--mrg-semantic-focus-width) solid var(--mrg-semantic-color-focus-ring);
    outline-offset: var(--mrg-semantic-focus-offset);
  }

  @media (forced-colors: active) {
    .mrg-citation > a,
    .mrg-citation > span:first-child,
    .mrg-citation[data-safe-url="false"] > span:first-child,
    .mrg-citation [data-slot="citation-source-detail"] {
      border-color: LinkText;
      color: CanvasText;
      background: Canvas;
    }
    .mrg-citation a:focus-visible {
      box-shadow: none;
      outline-color: Highlight;
    }
  }
}

import "./citation.css";

import { forwardRef, type HTMLAttributes, type ReactNode } from "react";

export interface CitationProps extends Omit<HTMLAttributes<HTMLSpanElement>, "children"> {
  /** Optional source excerpt rendered only when source detail is enabled. */
  readonly excerpt?: ReactNode;
  /** Consumer-supplied destination accepted only when it passes the safe URL policy. */
  readonly href: string;
  /** Positive one-based citation number used by visible and accessible labels. */
  readonly number: number;
  /** Adds source-name and excerpt note content; false removes the detail semantics. */
  readonly showSourceDetail?: boolean;
  /** Optional human-readable source name, falling back to the citation title. */
  readonly sourceName?: ReactNode;
  /** Required citation title included in the link's accessible name. */
  readonly title: string;
}

export function isSafeCitationUrl(value: string): boolean {
  const normalized = value.trim();
  if (
    normalized === "" ||
    [...normalized].some((character) => character === "\\" || character.codePointAt(0)! <= 31)
  ) {
    return false;
  }
  if (normalized.startsWith("/") && !normalized.startsWith("//")) return true;
  try {
    const url = new URL(normalized);
    return (
      (url.protocol === "https:" || url.protocol === "http:") &&
      url.username === "" &&
      url.password === ""
    );
  } catch {
    return false;
  }
}

export const Citation = forwardRef<HTMLSpanElement, CitationProps>(function Citation(
  { className, excerpt, href, number, showSourceDetail = false, sourceName, title, ...props },
  ref,
) {
  if (!Number.isSafeInteger(number) || number < 1) {
    throw new RangeError("Mergora Citation number must be a positive safe integer.");
  }
  const safe = isSafeCitationUrl(href);
  const external = safe && /^https?:\/\//iu.test(href.trim());

  return (
    <span
      {...props}
      className={className === undefined ? "mrg-citation" : `mrg-citation ${className}`}
      data-safe-url={safe}
      data-slot="citation"
      ref={ref}
    >
      {safe ? (
        <a
          aria-label={`Citation ${number}: ${title}`}
          href={href}
          rel={external ? "noreferrer noopener" : undefined}
          target={external ? "_blank" : undefined}
        >
          [{number}]
        </a>
      ) : (
        <span aria-label={`Citation ${number} is unavailable`}>[{number}]</span>
      )}
      {showSourceDetail ? (
        <span data-slot="citation-source-detail" role="note">
          <strong>{sourceName ?? title}</strong>
          {excerpt === undefined ? null : <span>{excerpt}</span>}
        </span>
      ) : null}
    </span>
  );
});

Citation.displayName = "Citation";
